stubApiCalls();
login();
cy.url().should('include', '/dashboard');
cy.get('[data-cy="btn-logout"]', {
  timeout: 15000
}).should('be.visible').click();
cy.url().should('include', '/login');

cy.intercept('GET', `${API}/**`, {
  forceNetworkError: true
});
login();
cy.url().should('include', '/dashboard');
cy.get('body').should('be.visible');

cy.request({
  method: 'POST',
  url: `${API}/auth/login`,
  body: {
    email: 'admin@uni.edu',
    password: 'admin123',
    tipo: 'admin'
  },
  failOnStatusCode: false
}).then(resp => {
  if (resp.status === 200) {
    expect(resp.body.success).to.be.true;
    expect(resp.body.data.tipo).to.equal('admin');
  }
});

cy.request({
  method: 'POST',
  url: `${API}/auth/login`,
  body: {
    email: 'admin@uni.edu',
    password: 'WRONG',
    tipo: 'admin'
  },
  failOnStatusCode: false
}).then(resp => {
  if (resp.status !== 503) {
    expect(resp.status).to.equal(401);
  }
});

cy.request({
  method: 'POST',
  url: `${API}/auth/login`,
  body: {
    email: 'test@test.com',
    password: 'pass',
    tipo: 'hacker'
  },
  failOnStatusCode: false
}).then(resp => {
  if (resp.status !== 503) {
    expect(resp.status).to.equal(400);
  }
});

setAuth();
